questions.gold_sparql:
SELECT (COUNT(DISTINCT ?inst) AS ?count) FROM <https://example.org/graphs/tier3/bc-universities> WHERE {
  ?inst a ?t .
  FILTER(?t IN (<https://example.org/tier3/bc/University>, <https://example.org/tier3/bc/College>, <https://example.org/tier3/bc/Institution>))
}

SELECT ?name FROM <https://example.org/graphs/tier3/bc-universities> WHERE {
  ?inst <https://example.org/tier3/bc/pred/name> ?name .
  ?inst a <https://example.org/tier3/bc/University> .
  FILTER(?name IN ("University of British Columbia", "Simon Fraser University", "University of Victoria", "University of Northern British Columbia"))
}
